/**
 * Generated types from the Sentinel API's OpenAPI schema.
 *
 * Do NOT edit `api.d.ts` by hand — it's regenerated by `npm run gen:types`.
 * This file re-exports the most useful aliases so callers don't have to
 * type the long `paths[...]["post"]` chains.
 */
export type { paths, components, operations } from './api.js';
import type { components } from './api.js';

/** All schemas declared in the API's OpenAPI spec. */
export type Schemas = components['schemas'];

/** Top-level resource shapes. */
export type ApprovalRecord = Schemas['ApprovalCreate'];
export type TenantSignupRequest = Schemas['TenantSignup'];

// Add more aliases as we expand surface area. The point is: hand-rolled
// duplicate types in src/index.ts should be migrated to references from
// this module, so a backend schema change shows up as a TS compile error.
